class Solution {
    public int minLength(String s) {
        int length = s.length();
        int result = length;
        String[] substrings = {"AB", "CD"};

        for (int i = 0; i < length; i++) {
            for (int j = 0; j < length; j++) {
                if (substrings.contains(s.substring(i, i + 2))) {
                    result--;
                    s = s.replace(s.substring(i, i + 2), "");
                }
            }
        }
        return result;
    }
}
```

